    ListNode* mergeTwoLists(ListNode* l1, ListNode* l2) {
        ListNode stHead;
        ListNode* pstCur = &amp;amp;stHead;
        while ((l1!=nullptr) &amp;amp;&amp;amp; (l2!=nullptr)) {
            if (l1-&amp;gt;val &amp;lt; l2-&amp;gt;val) {
                pstCur-&amp;gt;next = l1;
                l1=l1-&amp;gt;next;
            }
            else {
                pstCur-&amp;gt;next = l2;
                l2=l2-&amp;gt;next;
            }
            pstCur = pstCur-&amp;gt;next;
        }
        while (l1!=nullptr) {
            pstCur-&amp;gt;next = l1;
            l1=l1-&amp;gt;next;
            pstCur = pstCur-&amp;gt;next;
        }
        while (l2!=nullptr) {
            pstCur-&amp;gt;next = l2;
            l2=l2-&amp;gt;next;
            pstCur = pstCur-&amp;gt;next;
        }
        return stHead.next;
    }



