    int maxIncreaseKeepingSkyline(vector&amp;lt;vector&amp;lt;int&amp;gt;&amp;gt;&amp;amp; grid) {
        const int n = grid.size();
        vi viRowMax(n, 0);
        vi viColMax(n, 0);
        FOR (r, n) {
            FOR (c, n) {
                const int val = grid[r][c];
                if (val &amp;gt; viRowMax[r]) {
                    viRowMax[r] = val;
                }
                if (val &amp;gt; viColMax[c]) {
                    viColMax[c] = val;
                }
            }
        }

        int sum = 0;
        FOR (r, n) {
            FOR (c, n) {
                const int limit = min(viRowMax[r], viColMax[c]);
                if (limit &amp;gt; grid[r][c]) {
                    sum += limit - grid[r][c];
                }
            }
        }
        return sum;
    }



