    bool isValid(string s) {
        FOR(i, s.length()) {
            const char c = s[i];
            if (isOpening(c)) {
                m_S.push(s[i]);
                continue;
            }
            if (!m_S.empty()) {
                if (isPair(m_S.top(), c)) {
                    m_S.pop();
                }
                else return false;
            }
            else return false;
        }
        if (m_S.empty()) return true;
        else return false;
    }



