				const Atom_t &amp;amp;at1 = m_vAtoms[atI];
				const Atom_t &amp;amp;at2 = m_vAtoms[atJ];
				const int xVector = at1.x - at2.x;
				if (xVector != 0) continue;

				const int yVector = at1.y - at2.y;
