				const int yVector = at1.y - at2.y;
				if (yVector != 0) continue;

				const int xVector = at1.x - at2.x;
				if (xVector &amp;gt; 0) {
					const int dbldTime = xVector;
					m_vCrashes.push_back(Crash(dbldTime, ii(atI, atJ)));
